import React, { useEffect, useRef } from 'react';

const DNAHelix = () => {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);

  // DNA data representing your coding skills
  const dnaData = [
    { skill: 'React', color: '#00ffff', position: 0 },
    { skill: 'Node.js', color: '#ff0080', position: 1 },
    { skill: 'JavaScript', color: '#8000ff', position: 2 },
    { skill: 'Python', color: '#00ff41', position: 3 },
    { skill: 'CSS', color: '#0080ff', position: 4 },
    { skill: 'MongoDB', color: '#ffff00', position: 5 },
    { skill: 'PostgreSQL', color: '#ff0080', position: 6 },
    { skill: 'Docker', color: '#00ffff', position: 7 },
    { skill: 'AWS', color: '#8000ff', position: 8 },
    { skill: 'Git', color: '#00ff41', position: 9 }
  ];

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let time = 0;
    let particles = [];

    // Set canvas size
    const resizeCanvas = () => {
      canvas.width = canvas.offsetWidth * window.devicePixelRatio;
      canvas.height = canvas.offsetHeight * window.devicePixelRatio;
      ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    // Particle class for floating effects
    class Particle {
      constructor() {
        this.x = Math.random() * canvas.offsetWidth;
        this.y = Math.random() * canvas.offsetHeight;
        this.size = Math.random() * 2 + 1;
        this.speedX = (Math.random() - 0.5) * 0.5;
        this.speedY = (Math.random() - 0.5) * 0.5;
        this.color = dnaData[Math.floor(Math.random() * dnaData.length)].color;
        this.opacity = Math.random() * 0.5 + 0.2;
      }

      update() {
        this.x += this.speedX;
        this.y += this.speedY;

        if (this.x < 0 || this.x > canvas.offsetWidth) this.speedX *= -1;
        if (this.y < 0 || this.y > canvas.offsetHeight) this.speedY *= -1;
      }

      draw() {
        ctx.save();
        ctx.globalAlpha = this.opacity;
        ctx.shadowBlur = 10;
        ctx.shadowColor = this.color;
        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
      }
    }

    // Initialize particles
    for (let i = 0; i < 50; i++) {
      particles.push(new Particle());
    }

    // Animation function
    const animate = () => {
      ctx.clearRect(0, 0, canvas.offsetWidth, canvas.offsetHeight);
      
      const centerX = canvas.offsetWidth / 2;
      const centerY = canvas.offsetHeight / 2;
      const radius = 80;
      const helixHeight = 300;

      // Draw DNA strands
      for (let i = 0; i < dnaData.length; i++) {
        const skill = dnaData[i];
        const angle1 = (time + i * 0.3) * 0.02;
        const angle2 = angle1 + Math.PI;
        
        const y1 = centerY - helixHeight/2 + (i / dnaData.length) * helixHeight;
        const y2 = y1;
        
        const x1 = centerX + Math.cos(angle1) * radius;
        const z1 = Math.sin(angle1) * radius;
        const x2 = centerX + Math.cos(angle2) * radius;
        const z2 = Math.sin(angle2) * radius;

        // 3D effect - adjust size based on z position
        const scale1 = (z1 + radius) / (radius * 2);
        const scale2 = (z2 + radius) / (radius * 2);

        // Draw connecting line between strands
        ctx.save();
        ctx.strokeStyle = skill.color;
        ctx.shadowBlur = 15;
        ctx.shadowColor = skill.color;
        ctx.lineWidth = 2;
        ctx.globalAlpha = 0.6;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();
        ctx.restore();

        // Draw skill nodes
        [
          { x: x1, y: y1, scale: scale1, side: 'left' },
          { x: x2, y: y2, scale: scale2, side: 'right' }
        ].forEach(({ x, y, scale, side }) => {
          const nodeSize = 8 * scale;
          
          // Draw glowing node
          ctx.save();
          ctx.shadowBlur = 20;
          ctx.shadowColor = skill.color;
          ctx.fillStyle = skill.color;
          ctx.globalAlpha = scale;
          ctx.beginPath();
          ctx.arc(x, y, nodeSize, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();

          // Draw skill label
          if (scale > 0.7) {
            ctx.save();
            ctx.fillStyle = skill.color;
            ctx.font = `${12 * scale}px 'Fira Code', monospace`;
            ctx.textAlign = side === 'left' ? 'right' : 'left';
            ctx.shadowBlur = 10;
            ctx.shadowColor = skill.color;
            const textX = side === 'left' ? x - 15 : x + 15;
            ctx.fillText(skill.skill, textX, y + 4);
            ctx.restore();
          }
        });
      }

      // Update and draw particles
      particles.forEach(particle => {
        particle.update();
        particle.draw();
      });

      time++;
      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, []);

  return (
    <section id="dna-helix">
      <div className="dna-container">
        <div className="dna-header reveal">
          <div className="section-label">
            <span className="section-label-line"></span>
            <span>Digital DNA</span>
          </div>
          <h2 className="section-title">My Coding<br /><em>Genome</em></h2>
          <p className="dna-subtitle">
            Every developer has unique digital DNA. Here's mine - a double helix of technologies 
            that define my coding identity, constantly evolving and interconnected.
          </p>
        </div>
        
        <div className="dna-visualization reveal">
          <canvas ref={canvasRef} className="dna-canvas"></canvas>
          
          <div className="dna-legend">
            <div className="legend-title">Genetic Code Breakdown:</div>
            <div className="legend-grid">
              {[
                { name: 'Frontend DNA', skills: ['React', 'JavaScript', 'CSS'] },
                { name: 'Backend DNA', skills: ['Node.js', 'Python', 'PostgreSQL'] },
                { name: 'DevOps DNA', skills: ['Docker', 'AWS', 'Git'] },
                { name: 'Database DNA', skills: ['MongoDB', 'PostgreSQL'] }
              ].map((category, index) => (
                <div key={index} className="legend-category">
                  <div className="legend-category-name">{category.name}</div>
                  <div className="legend-skills">
                    {category.skills.map((skill, i) => (
                      <span key={i} className="legend-skill">{skill}</span>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="dna-stats reveal-stagger">
          <div className="dna-stat">
            <div className="stat-value">10+</div>
            <div className="stat-label">Technologies Mastered</div>
          </div>
          <div className="dna-stat">
            <div className="stat-value">∞</div>
            <div className="stat-label">Connections Made</div>
          </div>
          <div className="dna-stat">
            <div className="stat-value">24/7</div>
            <div className="stat-label">Evolution Active</div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default DNAHelix;
